var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"……응. 네가 없는 동안 집에 몇 번 찾아왔어. 클림트 씨.","JPN":"……うん。レアがいない間、何度か家に来てたよ。クリムトさん。","ENG":"...Yes. While you were away, Mr. Klimt came by our place several times.","TWN":"……嗯，你不在的時候，克里姆有來家裡找過我幾次。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"몇 번 찾아오다니……. 왜 그동안 말 안 한 거야?","JPN":"何度かって……なんで今まで黙ってたの？","ENG":"Several times? Why didn’t you ever tell me?","TWN":"他找過你幾次……那你怎麼都沒跟我說？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"공연에 참가하라는 제안 때문이었거든.","JPN":"公演に参加してくれっていう内容だったから。","ENG":"He wanted me to be a part of the performance.","TWN":"他來是想要我一起參與演出，"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"무대에 서 본 적은 위문 공연이나 채권 판촉 때문에 몇 번 정도라, 거절했지만.","JPN":"舞台は慰問公演とか、債権の販促で何度か立った程度だから断ったけど。","ENG":"I’ve performed on stage only a couple of times for bond promotions and morale-boosting concerts, so I turned him down.","TWN":"但我只有幾次在勞軍或是推銷債券時表演過的經驗，所以就拒絕他了。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"다른 얘기는 안 했어?","JPN":"他には何も言わなかった？","ENG":"You guys didn’t talk about anything else?","TWN":"他沒說其他的？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"으음, 글쎄. 아주머니께 음악에 대해 물어 보기도 했는데…….","JPN":"う～ん、そうね。おばさんに音楽について聞いてみたりはしてたけど……","ENG":"Hmm, well. He did talk to Madam a little bit about music...","TWN":"嗯，這個嘛，他是有跟伯母聊一些音樂的事……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그걸 내버려 뒀어? 너 우리 엄마가……!","JPN":"それを黙って見てたの？　私のお母さんが……！","ENG":"And you just let it happen? You know talking about that kind of stuff...!","TWN":"你就這樣放任他？你明知道我媽她……！"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"수, 숨겨서 미안해. 레아. 나쁜 뜻이 있어서 그런 건 아니야.","JPN":"だ、黙っててごめんね、レア。悪気があってそうしたわけじゃないの。","ENG":"S-Sorry for not telling you, Leah. I know it sounds bad, but it’s not like that.","TWN":"對不起，蕾亞，我不是故意要瞞著你的。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"너도 출장 다녀온 뒤로 바빴던 데다가, 아주머니도 다른 사람과 대화하는 게 즐거우셨던 것 같아서…….","JPN":"レアは出張帰りで忙しかったし、おばさんも他の人と話すのが楽しそうだったから……","ENG":"You’ve been so busy with your business trip and all, and well, she seemed so happy talking to other people so...","TWN":"你出差回來後就一直很忙，而且我看伯母也滿喜歡跟人聊天的……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"미안해, 안젤라. 엄마 병수발은 다 떠맡겨 놓고 화내서.","JPN":"ごめん、アンジェラ。お母さんの世話を任せっぱなしなのに怒っちゃって。","ENG":"I’m sorry, Angela. I just let you care for Mom and got angry with you.","TWN":"安潔拉.，對不起，我把照顧媽媽的事都推給你，竟然還對你發脾氣。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"괜찮아. 그만큼 너한테는 아주머니가 소중하다는 거잖아.","JPN":"いいのよ。それくらいレアにとっておばさんは大事ってことだから。","ENG":"It’s okay. I know how important Madam is to you.","TWN":"沒關係，我知道你很在意媽媽。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그런데……. 그 사람은 왜?","JPN":"でも……その人がどうかした？","ENG":"But... What’s with Mr. Klimt?","TWN":"不過……你怎麼會問起他的事？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"예전 직장에서 부탁을 받았어. 클림트와 관련된 일이야.","JPN":"昔の職場から頼まれてさ。クリムトと関係があるんだ。","ENG":"I got a request from my old workplace. It’s related to Mr. Klimt.","TWN":"以前的同事拜託我打聽有關克里姆的事。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"혹시 그 사람에 대해 뭔가 들은 거 없어? 어디 자주 간다거나, 취미라거나.","JPN":"あの人について何か聞いたことはない？　よく出かける場所とか、趣味とか。","ENG":"Did you by any chance hear anything about him while you were there? Such as what kind of places he went to or hobbies he had?","TWN":"你知道什麼有關於他的事嗎？譬如說他常去的地方，或是興趣之類的？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"글쎄……. 생각해 보면 개인적인 얘기는 거의 못 들은 것 같은데…….","JPN":"さあ……考えてみたら個人的な話はあまり聞いてないような……","ENG":"Well... Now that I think about it, I never really heard anything about his personal life...","TWN":"我也不太清楚……現在想想，他好像很少談到自己的事……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아, 맞다. 자기는 원래 수도에서 태어났다고 말한 적이 있어.","JPN":"あ、そうだ。自分が元々首都の生まれだって言ってたわ。","ENG":"Ah, right. I did hear he was born in Tanaberin.","TWN":"我想到了，他有提到他是在首都出生的。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"예전에 살던 동네에 가 봤더니 침식지대가 되어 있었다고 아쉬워했거든.","JPN":"昔住んでた街に行ってみたら、侵食地帯になってたって残念そうにしてた。","ENG":"And that when he went to see the old neighborhood he grew up in, he was devastated to see it had turned into a Corrupted Area.","TWN":"還說他回去以前住過的地方，結果發現那裡變成侵蝕地帶，覺得不勝唏噓。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"시내의 침식지대라…….","JPN":"市内の侵食地帯ねぇ……","ENG":"A Corrupted Area in the city...","TWN":"市區的侵蝕地帶嗎……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"고마워. 엄마는 좀 어때?","JPN":"ありがとう。お母さんはどう？","ENG":"Thanks. How’s Mom?","TWN":"謝謝你，我媽她還好媽？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"조금 진정되셔서 쉬고 계셔. 군인들이 너한테 무슨 짓을 할까 봐 걱정 많이 하시더라.","JPN":"少し落ち着いて休んでる。レアが軍人に何かされるんじゃないかってとても心配してるよ。","ENG":"She’s calmed down a bit and is just resting now. She was really worried about what those soldiers were going to do to you.","TWN":"她冷靜下來後現在在休息，她一直很擔心軍人會不會對你不利。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……발작은 안 일으키셔서 그나마 다행이네.","JPN":"……発作を起こさなくてよかった。","ENG":"...I’m glad she didn’t have a seizure.","TWN":"……沒發作就已經算是不幸中的大幸。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"다시 전화할게.","JPN":"また電話するよ。","ENG":"I’ll call again later.","TWN":"我再打給你，先這樣。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"응. 너무 무리하지는 마, 레아.","JPN":"うん。あまり無理しないようにね、レア。","ENG":"Ok. Don’t push yourself too hard, Leah.","TWN":"好，蕾亞，你不要太勉強自己喔。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……방금 통화한 사람, 혹시 애인이에요?","JPN":"……今電話した人、もしかして恋人ですか？","ENG":"...The person you were just talking to, was it your lover?","TWN":"……剛剛和你通話的人，是你的女朋友嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"친구야. 가족보다 더 가족 같은 친구지만.","JPN":"友達だよ。家族よりもっと家族のような友達だけど。","ENG":"Just a friend. Well, more like family, than a friend.","TWN":"是我女生的朋友啦！而且是比家人更像家人的朋友。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래요. 바람 피운 애인 추궁하는 것 같은 분위기라 그만.","JPN":"そうですか。浮気した恋人を責めるような雰囲気でしたからつい。","ENG":"Ahh okay. It just sounded like you were interrogating her as if she cheated on you or something.","TWN":"喔喔，因為我聽你問話的方式，就好像另一半偷吃在對質一樣。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"음? 들었어?","JPN":"ん？　聞こえた？","ENG":"Oh? You heard?","TWN":"嗯？你有聽到我們的對話？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네. 대놓고 통화하시길래 본의 아니게. 남들보다 귀가 밝은 편이라서요.","JPN":"はい。堂々と電話してましたから思わず。人より耳がいいんです。","ENG":"Yeah. I didn’t mean to, I just have really good ears.","TWN":"有，你就在我面前講，我不想聽都沒辦法，而且我的耳朵本來就比別人好。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"좋은 재능이네. 그것 덕분에 무공훈장을 받았던 걸까?","JPN":"いい才能だね。それのおかげで勲章をもらったのかな？","ENG":"That’s a very useful talent. Is that how you received the Medal of Honor?","TWN":"真是棒的才能，你是因為這樣才獲得授勳的嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아마도요? 전역증이었으면 더 좋았겠지만요.","JPN":"多分？　除隊証明書だったらもっとよかったんでしょうけど。","ENG":"Maybe? I would rather have just been discharged and let go.","TWN":"可能吧？但我更希望是退伍。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래도 아쉽게 됐네요. 카운터도 없이 저희 둘만 침식지대에 가는 건 자살 행위니까요.","JPN":"それでも残念ですね。カウンターもなしに二人だけで侵食地帯まで行くのは自殺行為ですから。","ENG":"Anyways, that’s a bummer. It’s suicide to go into a Corrupted Area without a Counter.","TWN":"不過真是遺憾，在沒有制裁者的情況下，我們自己去侵蝕地帶等於是去送死吧？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"지원을 요청하죠. 아니면 용병이라도 고용하거나.","JPN":"支援を頼みましょう。でなければ傭兵を雇うとか。","ENG":"We’ll need to call for backup, or maybe hire some mercenaries.","TWN":"請求支援吧？還是僱個傭兵也好？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>조용히</color> 끝내라고 했잖아. 요청해도 소용없을걸.","JPN":"<color=#ffd34c>静かに</color>終わらせろって言われたでしょ。頼んでも無駄だよ。","ENG":"They told us this operation needed to be done <color=#ffd34c>quietly</color>. Even if we request backup, they won’t send anyone.","TWN":"不是說要<color=#ffd34c>低調</color>嗎？就算請求支援也沒人會理我們的。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"실종자의 생가는 대정화전쟁 초기에 형성된 침식지대에 있어. 정기적으로 소탕하니까 침식체 걱정은 안 해도 돼.","JPN":"失踪者の生家は大浄化戦争の初期に形成された侵食地帯にある。定期的に片付けてるから侵食体の心配なら要らないよ。","ENG":"Mr. Klimt was born in the Corrupted Area formed in the days of the Great Purification War. That area is cleaned out routinely so you don’t need to worry about any Corrupted Objects.","TWN":"失蹤者的老家是在大淨化戰爭初期形成的侵蝕地帶，那裡都有定期在掃蕩，不需要擔心侵蝕體的問題。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"시간이 너무 늦었어요. 내일 다시 시작하죠.","JPN":"もうこんな時間です。続きは明日にしましょう。","ENG":"It’s getting late. We should start again tomorrow.","TWN":"現在很晚咧，明天再開始吧？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러니 더 서둘러야지. 실종 사건은 시간 싸움이야.","JPN":"だからもっと急ぐ必要があるの。失踪事件は一刻を争うから。","ENG":"Therefore we need to work faster. Missing person cases like this are a race against time.","TWN":"那我們更要加快動作，畢竟處理失蹤案件最關鍵的就是時間！"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"Sigh...","TWN":"哀哀……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네, 네. 보안국의 추진력에는 정말 당해낼 수가 없네요.","JPN":"はい、はい。保安局の推進力には到底敵いませんね。","ENG":"Okay... Okay. I get it. The Department of National Security never sleeps.","TWN":"好好好，安全局的行動力我真的是招架不住。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"제대로 협조하지 않으면 그 말도 보고서에 적어 줄게.","JPN":"ちゃんと協力しないと、その言葉も報告書に書いてやるから。","ENG":"If you don’t cooperate, I’ll mention it in the report.","TWN":"你不認真幫我的話，剛才那句話也會出現在報告裡。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"흐음……. 분명 여기 어디쯤인데…….","JPN":"う～ん……確かこのあたりなんだけど……","ENG":"Hmm… I'm sure it's here somewhere…","TWN":"嗯……應該就在這附近才對……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저기, 레버넌트 씨? 정확한 주소는 알고 온 거예요?","JPN":"あの、レヴナントさん？　住所はちゃんと知った上で来たんですよね？","ENG":"Uhh, Revenant? Do you know the exact address?","TWN":"我說亡靈小姐？你是知道地址才找到這裡來的嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"일선에서 빠진 지는 좀 됐지만, 중요 인물이라 기본적인 인적 사항은 조사해 뒀어.","JPN":"一線から退いて結構経つけど、重要人物だから基本的な個人情報は調べておいたの。","ENG":"It’s been awhile since I’ve been on the frontline like this but, Klimt is an important figure so I’d already performed a basic background check.","TWN":"雖然我離開第一線已經有段時間，但他畢竟是重要人物，所以我有調查一下他的身家。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아. 이 아파트야.","JPN":"あ。このマンションだ。","ENG":"Ah. this is the apartment.","TWN":"有了！就是這間公寓！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"상태로 봐선 <color=#ffd34c>아파트였던</color> 이라고 해야 하지 않을까요?","JPN":"見た目からすると、<color=#ffd34c>マンションだった物</color>って言うべきじゃないですか？","ENG":"Looking at its condition wouldn’t it be more accurate to say it <color=#ffd34c>was</color> an apartment?","TWN":"照這個狀態，應該是<color=#ffd34c>之前是公寓</color>才對吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇긴 하네.","JPN":"それもそうね。","ENG":"Fair enough.","TWN":"都可以啦～"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"망명 전 실종자의 주소지는 A동 401호였어. 의외로 고향을 각별하게 여긴 걸까.","JPN":"亡命する前の失踪者の住所はA棟の401号だった。意外と地元を大事に思ってたのかな？","ENG":"The address of Klimt before he fled the country was Building A, Room 401. Maybe he loved his hometown a lot.","TWN":"失蹤者流亡前的地址是A棟401號，原來他很在意老家嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래 봐야 난리가 나자마자 나 몰라라 해외로 도망친 사람이에요.","JPN":"そうだとしても大騒ぎになるや否や、知らんぷりで海外に逃げた人ですよ。","ENG":"Who cares. He’s the one that fled the country after all hell broke loose.","TWN":"但他一出事就立刻潛逃出境欸？！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"보안국이 하는 일은 그런 매국노를 혼내 주는 거 아니었나요?","JPN":"保安局の仕事って、そんな売国奴を叱ることじゃなかったんですか？","ENG":"Wasn’t it the National Security’s job to punish traitors like him?","TWN":"安全局的任務，不就是要教訓這種賣國賊嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"내가 맡은 일은 주로 정부의 승리를 돕는 거였어. 오해하지 마, 중사.","JPN":"私の仕事は主に政府の勝利のために手助けをすることだったの。誤解しないで、軍曹。","ENG":"Our job is to do whatever it takes for the government to win. Don’t misunderstand, Sergeant.","TWN":"我主要負責的部分，是協助政府取得勝利，請不要誤會，中士。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭐, 뭘 그렇게 빤히 쳐다 봐요?","JPN":"な、なんでそんなにジロジロ見てるんですか？","ENG":"W-what are you staring at?","TWN":"你…你幹嘛這樣盯著我看？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아니. 지금부터 안에 들어갈 거잖아. 그러니까, 어떤 위험이 있을지도 모르는 곳에.","JPN":"いや。今から中に入るでしょ？　つまり、どんな危険があるかわからないところに。","ENG":"Sergeant. We’re about to go inside. Inside a place that could very well be extremely dangerous.","TWN":"我們現在要進去裡面，也就是說，不知道進去後會遇到什麼狀況，"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"사격 준비 자세라거나 안 취해도 돼?","JPN":"射撃の態勢とか取らなくていいの？","ENG":"What are you doing? Shouldn’t you be a little more on guard?","TWN":"你不需要採取射擊姿勢嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……무방비한 척 하는 거죠. 만약 적이 있으면 레버넌트 씨보다 저를 먼저 노리게.","JPN":"……無防備なフリをするんですよ。もし敵がいたら、レヴナントさんより私を狙うように。","ENG":"...I’m just pretending to look defenseless. That way if we do encounter enemies they’ll shoot at me first while ignoring you.","TWN":"……我是裝得像沒預備一樣，要是敵人出現，我會比你還快瞄準敵人呢！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"호오……. 자신감이 대단한데?","JPN":"ほう……すごい自信だね。","ENG":"Whoa... You’re that confident in your abilities?","TWN":"哎唷……這麼有自信？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"알겠어. 그럼 잘 부탁할게.","JPN":"わかった。それじゃあよろしく。","ENG":"Okay then. I’ll be counting on you.","TWN":"OK！那就交給你囉！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……텅 비어 있네요.","JPN":"……空っぽですね。","ENG":"...It’s empty.","TWN":"……裡面什麼也沒有。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러게. 이상할 정도로 말이야.","JPN":"そうね。おかしいくらいに。","ENG":"Yeah... Something’s strange.","TWN":"對啊，空到一個可疑的程度。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L33_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"무슨 뜻이죠?","JPN":"どういう意味ですか？","ENG":"What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"오랫동안 버려진 곳치고는 바닥에 먼지가 너무 얕게 쌓여 있어. 누가 청소라도 하고 떠난 것처럼.","JPN":"長い間放置されている場所にしては、床に積もった埃が少ない。誰かが掃除してたみたいに。","ENG":"For a place that’s supposedly been abandoned for awhile, there isn’t enough dust. It’s like someone just cleaned up and left.","TWN":"這個地方荒廢這麼久，地上的灰塵卻不多，就像是有人剛打掃過一樣。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아무래도 누군가가 임시거점으로 사용했던 모양이야.","JPN":"どうやら誰かが臨時拠点として使ってたようね。","ENG":"I think it was used as a temporary base.","TWN":"感覺之前應該有人把這裡當作臨時據點。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"여기에 누가 있었다고요?","JPN":"ここに誰かが居たってことですか？","ENG":"Who was staying here though?","TWN":"這裡之前有人？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"침식체가 없다고 해도 일단은 침식지대잖아요. 단체로 사는 게 싫어졌다면 모를까.","JPN":"侵食体がいないとは言っても一応侵食地帯ですよ？　団体生活が嫌になったならともかく。","ENG":"Even if there aren’t any Corrupted Objects, it’s still a Corrupted Area. Maybe they didn’t like living near other people?","TWN":"就算沒有侵蝕體，但這裡再怎麼說也是侵蝕地帶，除非那個人不喜歡群體生活？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그 부분이 맹점이야.","JPN":"それが盲点なの。","ENG":"That’s the blind spot.","TWN":"你這麼說是有漏洞的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"오래된 침식지대는 이터니움 실드로 한동안 침식파를 견딜 수도 있고, 감시도 소홀해.","JPN":"古い侵食地帯はエタニウムシールドでしばらく侵食波にも耐えられるし、監視も緩い。","ENG":"You can withstand Corruption rays for a while with the Eternium Shield in the old Corrupted Area. Besides, surveillance is less strict.","TWN":"時間比較久的侵蝕地帶，可以用永恆之金盾抵抗侵蝕波一段時間，而且監視也相對鬆散。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"잠시 쓰고 버릴 생각이라면 흔적을 남길 필요도 없으니 안성맞춤이지.","JPN":"ちょっと使って捨てる気だったら、跡を残す必要もないから打ってつけよ。","ENG":"It’s perfect if you need a temporary place and don’t want to leave any traces after you’ve left.","TWN":"若只打算短期使用，也不會留下痕跡，豈不是正合適？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"침식지대에 대한 인식을 이용한단 말이죠. 침식 증후군만 걱정 안 하면 효율적이네요.","JPN":"侵食地帯の認識をこんな風に利用するんですか。侵食症候群の心配がないなら効率的ですね。","ENG":"It’s taking advantage of the stigma around Corrupted Areas. It’s an effective strategy if you aren’t worried about Corruption Syndrome.","TWN":"意思就是利用侵蝕地帶的特性對吧？不擔心侵蝕症候群的話，是滿聰明的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이런 건 태스크포스보다는 정보 기관에서 자주 쓰는 방식인데…….","JPN":"こういうのはタスクフォースより情報機関でよく使う手なんだけど……","ENG":"This tactic is often used by intelligence agencies more so than TASKFORCE...","TWN":"這比較像是情報機關會用的手法，應該不是特遣勢力……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"클림트……. 정말 망명했던 본인은 맞는 걸까.","JPN":"クリムト……本当に亡命してきた本人なのかな。","ENG":"Klimt... Was he really the one who fled the country?","TWN":"克里姆……真的是之前流亡的那個人嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트 씨, 그럼 저는 위층 좀 돌아보고 올게요.","JPN":"レヴナントさん、それじゃあ私は上の階を見回ってきます。","ENG":"Revenant, I’ll take a look around upstairs.","TWN":"亡靈小姐，那我先去樓上看看。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"응? 아, 부탁할게.","JPN":"うん？　ええ、お願い。","ENG":"Huh? Oh, please do.","TWN":"嗯？喔，好，麻煩你了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"흐아암…….","JPN":"ふわあ……","ENG":"Yawn...","TWN":"哀哀哀……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"결국에는 이래저래 부려먹히네. 예상은 했지만.","JPN":"結局はあれこれこき使われてる。予想はしてたけど。","ENG":"In the end, I’m being forced to go around doing all these little things. I expected it but still...","TWN":"結果事情根本一大堆嘛，雖然早就有預料到會這樣。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"귀찮을 일 없게 적당히 무능하지만 화나지는 않는 녀석……. 정도로만 버티다가 작별할 생각이었는데.","JPN":"面倒事のないように、適当に、無能だけど怒るほどではない奴……程度でやり過ごして別れるつもりだったのに。","ENG":"Well, I was only going to be moderately incompetent, not annoying or anything like that. I was planning on just putting it up for a bit and then saying goodbyes.","TWN":"但我就已經裝得很沒用，想說不要自找麻煩，可是她也都不生氣……我本來想說撐一下就走人的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네가 도와 주면 좋겠어, 중사.","JPN":"君に助けてほしいんだ、軍曹。","ENG":"I need your help, Sergeant.","TWN":"中士，我希望你可以幫我。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"다른 사람이 아니라, 네가.","JPN":"他の誰でもなく、君に。","ENG":"Not someone else, YOU.","TWN":"不是別人，而是你！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……그런 말까지 해야 하는 시점에서 쓸모없는 인간 확정이라는 걸 모르나?","JPN":"……あんなことまで言わなきゃいけない時点で使えない人間確定ってこと、わかってないのかな？","ENG":"...Having to say something like that, couldn’t she tell I’m completely worthless?","TWN":"……我還讓她說出那種話，這樣她還不知道我很沒用嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭐, 레버넌트 씨가 고민할 동안 나는 으슥한 데에서 잠깐 좀 쉴까.","JPN":"まあ、レヴナントさんが悩んでる間、私は隅っこでちょっと休もう。","ENG":"Anyway, how about a nice little break while Revenant is thinking.","TWN":"就這樣吧！趁她在想那些有的沒有的時候，我就找個安靜的地方休息一下吧！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"나 같이 기본도 모르는 초짜가 붙어 있어 봐야 짐이지. 응, 응.","JPN":"私みたいな基本すらわからない素人がついていてもお荷物になるだけだよ。うん、うん。","ENG":"A newb like me that doesn’t even know the basics won’t really help. Yes, yes.","TWN":"像我這種什麼都不懂的菜鳥，跟在她旁邊只會成為她的負擔啦！沒錯沒錯！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"응……?","JPN":"うん……？","ENG":"Huh?","TWN":"嗯……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어……? 어어……?","JPN":"え……？　ええ……？","ENG":"Wha...? What’s that!?","TWN":"欸……？欸欸欸……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"꺄아아악!?","JPN":"きゃああっ！？","ENG":"Kyaaaaaakkk!?","TWN":"哇啊啊！？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"크리스! 부비트랩이라도 건드렸어?!","JPN":"クリス！　ブービートラップにでも触った！？","ENG":"Chris! Did you trigger a boobytrap?!","TWN":"克莉絲！你是誤觸詭雷嗎？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 아니에요! 레버넌트 씨! 위층에 치, 치치, 침식체가……!","JPN":"ち、違います！　レヴナントさん！　上の階にし、しし、侵食体が……！","ENG":"N-no, I-it wasn’t me! Revenant! Upstairs, It’s a Co-Corrup-Corrupted Object!","TWN":"沒…沒有啊！亡靈小姐！樓上有侵…侵…侵蝕體……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"침식체?","JPN":"侵食体？","ENG":"Corrupted Object?","TWN":"侵蝕體？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"저건…… <color=#ffd34c>슈터</color>잖아? 왜 2종 침식체가 이런 데 있는 거지?","JPN":"あれは……<color=#ffd34c>シューター</color>？　第2種侵食体がなんでこんなところに？","ENG":"That’s a... <color=#ffd34c>Shooter</color>, right? Why is there a Category 2 C.O. here?","TWN":"那……不是<color=#ffd34c>射手</color>嗎？2類侵蝕體怎麼會在這種地方？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그게 중요한 게 아니잖아요! 어서 도망쳐야 돼요!","JPN":"それどころじゃないでしょう！　早く逃げないと！","ENG":"That’s not important right now! We’ve got to get out of here!","TWN":"現在重點不是這個吧！先逃命再說啦！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"기다려!","JPN":"待って！","ENG":"Wait!","TWN":"先等一下！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"등을 돌리면 적의 공격에 무방비해져. 2종 침식체라면 도망쳐 봤자 금방 따라잡힐 테고.","JPN":"背を向けたら敵の攻撃に対して無防備になる。第2種侵食体なら逃げてもすぐ追いつかれちゃうし。","ENG":"If we show our back to the enemy, we’ll be completely helpless. If it’s a Category 2 C.O., it’ll catch up with us in no time.","TWN":"怎麼可以背對敵人，這樣豈不是毫無防備！而且敵人是2類侵蝕體，就算我們逃跑，它也很快可以追上來。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래서 싸우자고요? 같이 개죽음 당할 일 있어요?","JPN":"だから戦おうって言うんですか？　無駄死にするだけでしょう！","ENG":"So you’re saying we should fight it? Seriously, that’s suicide!","TWN":"所以現在是要跟它打的意思？你是想同歸於盡嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"우선 피하기나 해!","JPN":"まずは避けて！","ENG":"Just focus on dodging its attacks!","TWN":"先躲起來再說！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"콜록……! 콜록!!","JPN":"ゲホ……！　ゲホゲホ！！","ENG":"*Cough...!* *Cough!!*","TWN":"咳咳……！咳咳！！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"중사! 시선은 내가 끌게!","JPN":"軍曹！　私が注意を引く！","ENG":"Sergeant! I’ll draw its attention!","TWN":"中士！我來引開它的注意！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네가 공격 받을 일은 없어! 거저 받은 훈장이 아니란 걸 여기서 증명해 봐!","JPN":"軍曹が攻撃されることはない！　ただで手に入れた勲章じゃないってのをここで証明してみて！","ENG":"You won’t get attacked! Now, show me why you were given that medal!","TWN":"你不會有事的！現在就是證明自己的好機會，你的勳章可不是拿假的！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};